mapper.select:
SELECT DISTINCT p.* FROM sys_permission p WHERE p.status = 1 AND p.permission_type IN ('directory', 'menu') AND ( -- 直接分配的权限 EXISTS ( SELECT 1 FROM sys_role_permission rp INNER JOIN sys_role r ON rp.role_id = r.role_id WHERE r.role_code IN
#{roleCode}
AND rp.permission_id = p.permission_id ) OR -- 递归查询所有父目录 EXISTS ( SELECT 1 FROM sys_permission child INNER JOIN sys_role_permission rp ON child.permission_id = rp.permission_id INNER JOIN sys_role r ON rp.role_id = r.role_id WHERE r.role_code IN
#{roleCode}
AND child.parent_id = p.permission_id ) OR -- 递归查询所有祖父目录 EXISTS ( SELECT 1 FROM sys_permission child INNER JOIN sys_permission parent ON child.parent_id = parent.permission_id INNER JOIN sys_role_permission rp ON child.permission_id = rp.permission_id INNER JOIN sys_role r ON rp.role_id = r.role_id WHERE r.role_code IN
#{roleCode}
AND parent.parent_id = p.permission_id ) ) ORDER BY p.sort_order ASC
